import 'package:injectable/injectable.dart'; import '../platform/platform_info.dart'; import '../services/keep_alive_service.dart'; import '../utils/app_logger.dart'; @injectable class BootManager { final PlatformInfo _info; final KeepAliveService _keepAlive; BootManager(this._info, this._keepAlive); Future<void> onBoot() async { AppLogger.info('Boot: ${_info.deviceName}'); await _keepAlive.startForegroundService(); } }